class PieceClass{
	constructor(x, y, type, color, imgName, id){
			this.x = x;
			this.y = y;
			this.type = type;
			this.color = color;
			this.imgName = imgName;
			this.id = id;
			this.alreadyMoved = false;
		}
}

export default PieceClass
